import React from 'react'
import { Link } from 'react-router-dom';

const Footer = () => {

  return (
    <div className="bg-grey-dark text-light">
      <div className="mt-5 container pt-5 pb-3">
        <div className="row">
          <div className="col-6">
            <div className="footerLinks">
              <Link className="link" to='/movieshub/movie'>Movie</Link>
              <Link className="link" to='/movieshub/tv'>TV Shows</Link>
              <Link className="link" to='/movieshub/people'>People</Link>
            </div>
            <div className="mt-4">
              {new Date().getFullYear()} &copy; Hit Patel.
            </div>
          </div>
          <div className="col-6">
            <div className="pointer" onClick={() => window.scrollTo(0, 0)}>Back to top &#8599;</div>
          </div>
        </div>
      </div>
    </div>
  )
}

export default Footer;
